import React from 'react';

const AboutMe = () => {
  const items = [
    {
      label: 'Age',
      value: '19 years old',
    },
    {
      label: 'Hobbies',
      value: 'Watching anime, Working out, and Playing videogames',
      images: [
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg', alt: 'Anime' },
        { src: 'https://img.joomcdn.net/3951999955bde0c8ac0a989a3d481890d9b794cd_original.jpeg', alt: 'Bodybuilding' },
        { src: 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcQ0WSAO7K7N54BRF4t5rcez6eaZuHPYT88DMA&s', alt: 'Videogame' },
      ],
    },
    {
      label: 'Interest',
      value: 'Bodybuilding, Anime, Kdrama, and Alternative R&B',
      images: [
        { src: 'https://st2.depositphotos.com/5894210/11673/v/450/depositphotos_116738402-stock-illustration-vector-illustration-of-bodybuilder-on.jpg', alt: 'Bodybuilding' },
        { src: 'https://i.redd.it/both-of-these-fall-under-the-carried-by-animation-v0-gjip3tvumfpe1.jpg', alt: 'Anime' },
        { src: 'https://preview.redd.it/netflix-the-glory-part-2-character-poster-premieres-march-10-v0.jpg', alt: 'Kdrama' },
        { src: 'https://m.media-amazon.com/images/I/71LIeQ11qqL._AC_UF894,1000_QL80_.jpg', alt: 'R&B' },
      ],
    },
  ];

  return (
    <section
      id="About-Me"
      className="min-h-screen flex flex-col justify-center items-center px-5 py-24 bg-[#0a0f2e]/70 backdrop-blur-sm"
    >
      <h1 className="font-bold text-4xl text-white text-center mb-12">
        More About Me
      </h1>

      <div className="w-full max-w-3xl flex flex-col gap-6">
        {items.map((item, i) => (
          <div
            key={i}
            className="rounded-xl p-6 transition hover:-translate-y-1"
            style={{
              background: 'rgba(0,55,145,0.15)',
              borderLeft: '4px solid #0d6efd',
              border: '1px solid rgba(0,112,204,0.25)',
            }}
          >
            {/* TEXT */}
            <p className="text-white text-base">
              <b className="text-[#4da3ff]">{item.label}:</b>{' '}
              <span className="text-[#b8c7e6]">{item.value}</span>
            </p>

            {/* IMAGES */}
            {item.images && (
              <div className="flex gap-4 mt-4 flex-wrap">
                {item.images.map((img, j) => (
                  <img
                    key={j}
                    src={img.src}
                    alt={img.alt}
                    className="w-36 h-24 object-cover rounded-lg border border-blue-500/30"
                  />
                ))}
              </div>
            )}
          </div>
        ))}
      </div>
    </section>
  );
};

export default AboutMe;
